    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        // Act
        var result = _service.GetOrder("non-existent-id");

        // Assert
        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_WithMultipleOrders_ReturnsAllForCustomer()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 1));
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-2", items);

        // Act
        var orders = _service.GetOrdersByCustomer("cust-1");

